patch:
--- a/sync_counter.v
+++ b/sync_counter.v
@@ -1,13 +1,13 @@
 module sync_counter_16bit(
   input clk,
   input rst_n,
   output reg [15:0] count
 );

-  always @(posedge clk) begin
+  always @(posedge clk or negedge rst_n) begin
     if (!rst_n)
       count <= 16'h0000;
     else
       count <= count + 1;
   end

 endmodule

before_code:
module sync_counter_16bit(
  input clk,
  input rst_n,
  output reg [15:0] count
);

  always @(posedge clk) begin
    if (!rst_n)
      count <= 16'h0000;
    else
      count <= count + 1;
  end

endmodule

after_code:
module sync_counter_16bit(
  input clk,
  input rst_n,
  output reg [15:0] count
);

  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      count <= 16'h0000;
    else
      count <= count + 1;
  end

endmodule
